import{_ as s,o as e,c as t,a2 as i}from"./chunks/framework.BWuWLRhz.js";const k=JSON.parse('{"title":"安装、商户与监听 App","description":"","frontmatter":{},"headers":[],"relativePath":"gtpay/setup.md","filePath":"gtpay/setup.md","lastUpdated":null}'),p={name:"gtpay/setup.md"};function n(l,a,d,o,c,h){return e(),t("div",null,[...a[0]||(a[0]=[i(`<h1 id="安装、商户与监听-app" tabindex="-1">安装、商户与监听 App <a class="header-anchor" href="#安装、商户与监听-app" aria-label="Permalink to &quot;安装、商户与监听 App&quot;">​</a></h1><h2 id="安装要求" tabindex="-1">安装要求 <a class="header-anchor" href="#安装要求" aria-label="Permalink to &quot;安装要求&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>要求</th></tr></thead><tbody><tr><td>服务端版本</td><td>1.12.2 到当前最新版</td></tr><tr><td>核心</td><td>正常运行并完成授权的 GTCore</td></tr><tr><td>安卓设备</td><td>能长期运行 <code>GT收款守护</code>，并允许读取微信、支付宝到账通知</td></tr><tr><td>收款码</td><td>微信、支付宝个人收款码 PNG 或 JPEG 图片</td></tr></tbody></table><p>GTPay 由 GTCore 自动加载，不需要把 GTPay JAR 放入 <code>plugins</code>。</p><h2 id="创建服务器凭证" tabindex="-1">创建服务器凭证 <a class="header-anchor" href="#创建服务器凭证" aria-label="Permalink to &quot;创建服务器凭证&quot;">​</a></h2><p>私聊机器人：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>创建GTPay 服务器名称</span></span></code></pre></div><p>示例：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>创建GTPay 生存一区</span></span></code></pre></div><p>机器人只会给已经拥有 GTPay 的 QQ 创建凭证。未拥有 GTPay 时会返回：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你当前未拥有GTPay</span></span></code></pre></div><p>返回内容中四项配置的用途：</p><table tabindex="0"><thead><tr><th>配置</th><th>填写位置</th></tr></thead><tbody><tr><td><code>merchant_id</code></td><td>服务端本地管理页、监听 App</td></tr><tr><td><code>server_id</code></td><td>服务端本地管理页</td></tr><tr><td><code>server_key</code></td><td>服务端本地管理页</td></tr><tr><td><code>monitor_key</code></td><td>服务端本地管理页、监听 App</td></tr></tbody></table><p>密钥只通过私聊查询，不要发到群内、工单截图或公开配置中。</p><h2 id="多服务器配置" tabindex="-1">多服务器配置 <a class="header-anchor" href="#多服务器配置" aria-label="Permalink to &quot;多服务器配置&quot;">​</a></h2><p>同一服主可以创建多个服务器：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>创建GTPay 生存一区</span></span>
<span class="line"><span>创建GTPay 生存二区</span></span>
<span class="line"><span>创建GTPay RPG一区</span></span></code></pre></div><p>每个服务器都要使用自己对应的四项配置。不要把一区的 <code>server_id</code>、<code>server_key</code> 与二区的 <code>merchant_id</code> 混用。</p><h2 id="跨服同步的多个区" tabindex="-1">跨服同步的多个区 <a class="header-anchor" href="#跨服同步的多个区" aria-label="Permalink to &quot;跨服同步的多个区&quot;">​</a></h2><p>5 台独立服务端如果属于同一个跨服网络，并且需要合并累计赞助、排行和礼包限购，5 台都填写同一套 GTPay 凭证：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>merchant_id  相同</span></span>
<span class="line"><span>server_id    相同</span></span>
<span class="line"><span>server_key   相同</span></span>
<span class="line"><span>monitor_key  相同</span></span></code></pre></div><p>这表示这些区在 GTPay 中属于同一个收款主体。各区仍然是独立服务端，订单由创建订单的那台服务端负责查询和发放，其他区不会抢发订单。监听 App 使用同一个 <code>merchant_id</code> 和 <code>monitor_key</code> 即可。</p><p>在 5 台服务端的 <code>plugins/GTPay/config.yml</code> 中，把存储方式改成 MySQL 或 Redis，并填写同一个数据库或 Redis：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">storage</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  mode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mysql&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  node-id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;auto&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  cluster-id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;auto&quot;</span></span></code></pre></div><p><code>cluster-id</code> 使用 <code>auto</code> 时按 <code>merchant_id</code> 隔离。同一组跨服服务器保持一致；不要给同一组服务器填写不同的 <code>cluster-id</code>。<code>node-id</code> 保持 <code>auto</code>，每台服务端会根据 GTCore 设备和服务端端口生成自己的节点标识。</p><p>存储配置由 GTPay 保存，MySQL、Hikari、Redis 和 Lettuce 运行库由 GTCore 提供，不需要额外上传数据库驱动 JAR。修改存储方式、数据库或集群标识后，重启对应的 Minecraft 服务端。</p><p>同步内容包括：</p><ul><li>已完成订单。</li><li>礼包个人购买上限和全服购买上限。</li><li>永久、日、周、月、年和活动累计赞助金额。</li><li>累计赞助排行和 PAPI 排名变量。</li><li>累计赞助奖励领取记录。</li></ul><p>通常在同步间隔内生效，默认间隔为 10 秒。</p><p>如果多个区需要分别统计、分别查看订单或分别使用不同收款主体，为每个区创建独立的 GTPay 凭证，并使用独立的 <code>cluster-id</code> 或独立数据库。</p><p>使用 <code>local</code> 存储时，订单和累计数据只保存在当前服务端，不会跨服同步。</p><p>查询全部服务器：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>查询GTPay</span></span></code></pre></div><p>查询指定服务器：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>查询GTPay 生存一区</span></span></code></pre></div><h2 id="打开本地管理页" tabindex="-1">打开本地管理页 <a class="header-anchor" href="#打开本地管理页" aria-label="Permalink to &quot;打开本地管理页&quot;">​</a></h2><p>在 Minecraft 服务器控制台执行：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gtpay web open</span></span></code></pre></div><p>控制台会返回一次性访问地址。在运行 Minecraft 服务端的机器上打开该地址。</p><p>本地管理页包含：</p><ul><li>概览。</li><li>连接配置。</li><li>本地、MySQL、Redis 存储配置。</li><li>点券充值配置。</li><li>礼包配置。</li><li>累计赞助配置。</li><li>多文件 GUI 配置。</li><li>近期订单与发放重试。</li></ul><p>页面不显示服务地址，也没有服务地址填写项。</p><p>完成配置后可以关闭：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gtpay web close</span></span></code></pre></div><p>查看管理页状态：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gtpay web status</span></span></code></pre></div><h2 id="放置收款码" tabindex="-1">放置收款码 <a class="header-anchor" href="#放置收款码" aria-label="Permalink to &quot;放置收款码&quot;">​</a></h2><p>默认文件位置：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>plugins/GTPay/qrcode/wechat.png</span></span>
<span class="line"><span>plugins/GTPay/qrcode/alipay.png</span></span></code></pre></div><p>图片要求：</p><ul><li>使用微信、支付宝正常可用的个人收款码。</li><li>使用正方形 PNG。</li><li>图片边缘不要带大段文字、广告或复杂边框。</li><li>文件不要超过 4 MB。</li><li>图片必须放在 <code>qrcode</code> 文件夹中。</li></ul><p>如果要修改文件名，在 <code>config.yml</code> 或本地管理页修改：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">qrcode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  directory</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;qrcode&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  wechat</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;wechat.png&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  alipay</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;alipay.png&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  display-in-map</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre></div><p>收款码只保存在服主服务器本地，不需要上传。</p><h2 id="配置监听-app" tabindex="-1">配置监听 App <a class="header-anchor" href="#配置监听-app" aria-label="Permalink to &quot;配置监听 App&quot;">​</a></h2><p>在安卓设备安装并启动 <code>GT收款守护</code>。</p><p>App 中只需要填写：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>merchant_id</span></span>
<span class="line"><span>monitor_key</span></span></code></pre></div><p>然后完成以下设置：</p><ol><li>授予通知使用权。</li><li>允许 App 在后台运行。</li><li>关闭系统对该 App 的省电限制。</li><li>保证微信、支付宝能正常显示到账通知。</li><li>确认 App 显示连接成功。</li></ol><p>App 不填写激活码、<code>server_key</code> 或后台地址。</p>`,61)])])}const u=s(p,[["render",n]]);export{k as __pageData,u as default};
